            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 0x6303686EB534AA54ULL) + aPhaseEOrbiterUpdateSaltB[((aIndex + 14U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0x8E29F384E5AFA363ULL;
