            aOrbiterB = ((aOrbiterB ^ aOrbiterD) ^ 0x058A3C37086426E5ULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0x27045653DA0D5E1DULL), 35U);
