            aOrbiterK = (aOrbiterK ^ aOrbiterB) ^ 0xCBDA704B40D9473BULL;
            aOrbiterK = RotL64((aOrbiterK * 0xAE8A997D243644A7ULL), 29U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterB) + 0x30BAA9E221E9F1AAULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 0xD4BDB115ECB85494ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xC2AB0340F9A5D20FULL), 3U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterJ) + 0x75C5F5159ACAC111ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0x7DE05CB39A3E90BBULL;
            aOrbiterE = RotL64((aOrbiterE * 0x952F4ED90FEB5535ULL), 43U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 0x8374346F77E8FE9DULL;
