            //
            aWandererK = aWandererK + ((((RotL64(aPrevious, 39U) + RotL64(aOrbiterE, 37U)) + aOrbiterI) + RotL64(aCarry, 27U)) + aPhaseGWandererUpdateSaltE[((aIndex + 7U)) & S_SALT1]);
